"""Migrations for 3.0.0 release."""

import asyncio

from netskope.common.utils import DBConnector, Collections
from netskope.common.models import TenantUpdate, PollIntervalUnit
from netskope.common.api.routers.tenants import update_tenant

if __name__ == "__main__":
    connector = DBConnector()
    loop = asyncio.get_event_loop()

    # update tenants
    for tenant in connector.collection(Collections.NETSKOPE_TENANTS).find({}):
        if not isinstance(tenant.get("checkpoint", None), dict):
            print(f"Updating checkpoints for tenant {tenant['name']}.")
            connector.collection(Collections.NETSKOPE_TENANTS).update_one(
                {"name": tenant["name"]},
                {
                    "$set": {
                        "lockedAt": {"alerts": None, "events": None},
                        "checkpoint": {
                            "alert": tenant["checkpoint"],
                            "event": None,
                        },
                    }
                },
            )

        print(f"Updating poll interval for tenant {tenant['name']}.")
        loop.run_until_complete(
            update_tenant(
                TenantUpdate(
                    name=tenant["name"],
                    pollInterval=30,
                    pollIntervalUnit=PollIntervalUnit.SECONDS,
                )
            )
        )

    # update crowdstrike configurations
    for configuration in connector.collection(Collections.CONFIGURATIONS).find(
        {"plugin": "netskope.plugins.Default.crowdstrike.main"}
    ):
        print(
            f"Updating CTE CrowdStrike configuration {configuration['name']}."
        )
        connector.collection(Collections.CONFIGURATIONS).update_one(
            {"name": configuration["name"]},
            {
                "$set": {
                    "parameters.platforms": ["windows", "mac", "linux"],
                    "parameters.action": "no_action",
                }
            },
        )

